MonsterConfig = {}

MonsterConfig.MonsterData = {} --怪物配置

--local inspect = require "util.inspect"

function MonsterConfig:init(config)
    for _, configData in pairs(config) do
        local monster = {}
        monster.id = tonumber(configData.id) or 0 --id
        monster.name = configData.name --名称
        monster.actor = configData.actor --模型资源
        monster.aiFile = configData.aiFile --AI
        monster.hp = tonumber(configData.hp) or 0 --生命值
        monster.moveSpeed = StringUtil.split(configData.moveSpeed, "#") --移动速度
        monster.nightMoveSpeed = tonumber(configData.nightMoveSpeed) or 0  --夜晚移动速度
        --monster.jumpHeight = tonumber(configData.jumpHeight) or 0 --跳跃高度
        monster.attack = tonumber(configData.attack) or 0 --攻击力
        monster.nightAttack = tonumber(configData.nightAttack) or 0 --夜晚攻击力
        monster.attackDistance = tonumber(configData.attackDistance) or 0 --攻击距离
        monster.attackCd = tonumber(configData.attackCd) or 0 --攻击间隔
        --monster.knockBackDistance = tonumber(configData.knockBackDistance) or 0 --击退距离
        monster.infectRate = tonumber(configData.infectRate) or 0 --感染概率
        monster.specialEffectId = tonumber(configData.specialEffectId) or 0 --特殊效果
        monster.nightPatrolDistance = tonumber(configData.nightPatrolDistance) or 0 --夜晚视野范围
        monster.chaseRange = tonumber(configData.chaseRange) or 0 --追击范围
        --monster.addHp = tonumber(configData.addHp) or 0 --生命恢复
        monster.soundA = tonumber(configData.soundA) or 0 --低吼声
        monster.soundB = tonumber(configData.soundB) or 0 --攻击音效
        monster.soundC = tonumber(configData.soundC) or 0 --死亡音效
        monster.soundAInterval = self:parseSoundInterval(configData.soundAInterval) --低吼间隔
        monster.soundADistance = configData.soundADistance --低吼距离
        --monster.exp = tonumber(configData.exp) or 0 --经验
        monster.drops = StringUtil.split(configData.drops, "#")  --掉落物品
        monster.dropsProbability = StringUtil.split(configData.dropsProbability, "#")  --掉落概率
        --monster.defense = tonumber(configData.defense) or 0 --防御力
        monster.attackCount = tonumber(configData.attackCount) or 0 --攻击系数
        --monster.attackSpeed = tonumber(configData.attackSpeed) or 0 --攻击速度
        monster.isAutoAttack = tonumber(configData.isAutoAttack) or 0 --是否自动攻击
        monster.patrolDistance = tonumber(configData.patrolDistance) or 0 --视野范围
        monster.skillId = tonumber(configData.skillId) or 0 --技能id
        monster.skillCd = tonumber(configData.skillCd) or 0 --技能释放cd
        --monster.effect = StringUtil.split(configData.effect, "#") --攻击后效果
        monster.isBoss = tonumber(configData.isBoss) or 0 --是否是boss
        monster.attackType = tonumber(configData.attackType) or 0 --攻击类型
        monster.nightBuff = tonumber(configData.nightBuff) or 0 --夜晚buff
        monster.bombEffect = configData.bombEffect --远程攻击效果
        monster.score = tonumber(configData.score) or 0--击杀后的分数
        monster.remoteSpeedFactor = tonumber(configData.remoteSpeedFactor) or 1
        table.insert(self.MonsterData, monster)
        --HostApi.log("MonsterConfig:init " ..
        --        monster.id .. " " .. monster.name .. " ".. monster.actor .. " ".. monster.attackType)
    end

    --table.sort(self.MonsterData, function(p1, p2)
    --    return p1.id < p2.id
    --end)

    MonsterConfig:prepareMonster()
end

function MonsterConfig:parseSoundInterval(str)
    local result = {}

    local result_1 = StringUtil.split(str, "#")
    for i, v in pairs(result_1) do
        local range = StringUtil.split(v, ",")
        table.insert(result, range)
    end

    --测试
    --for i = 1, #result do
    --    HostApi.log(result[i][1] .. " " .. result[i][2])
    --end
    --HostApi.log("****************************************")

    return result
end

function MonsterConfig:prepareMonster()
    for _, v in pairs(self.MonsterData) do
        local monster = MonsterSetting.new()
        monster.monsterId = v.id
        monster.monsterBtTree = v.aiFile
        monster.actorName = v.actor
        if v.isBoss == 0 then
            monster.monsterType = 2
        else
            monster.monsterType = 3
        end
        monster.attackType = v.attackType
        monster.isAutoAttack = v.isAutoAttack
        monster.attackDistance = v.attackDistance
        monster.attackCd = v.attackCd
        monster.attackCount = v.attackCount
        monster.moveSpeed = v.moveSpeed[1]
        monster.patrolDistance = v.patrolDistance
        monster.skillId = v.skillId
        monster.skillCd = v.skillCd
        monster.chaseRange = v.chaseRange
        monster.bombEffect = v.bombEffect
        monster.remoteSpeedFactor = v.remoteSpeedFactor
        HostApi.addMonsterSetting(monster)
        --HostApi.log(string.format("HostApi.addMonsterSetting monsterId:%d senseRange:%d chaseRange:%d patrolRange:%d attackType:%d",
        --        monster.monsterId, monster.senseRange, monster.chaseRange, monster.patrolDistance, monster.attackType))
    end
end

