function MonsterConfig:getMonsterConfig(id)
    for _, vMonsterData in pairs(self.MonsterData) do
        if vMonsterData.id == id then
            --HostApi.log("MonsterConfig:getMonsterConfig " .. id .. " " .. vMonsterData.actor)
            return vMonsterData
        end
    end

    --HostApi.log("MonsterConfig:getMonsterConfig return nil " .. id)

    return nil
end

return MonsterConfig